import { existsSync, readFileSync } from 'fs';
import { join } from 'path';

const DURATION_MS = 10 * 60 * 1000; // 10 minutes

function loadBotEnv(botName: string) {
    const envPath = join(process.cwd(), 'bots', botName, 'bot.env');
    if (!existsSync(envPath)) throw new Error(`No bot.env for ${botName}`);
    const content = readFileSync(envPath, 'utf-8');
    const env: Record<string, string> = {};
    for (const line of content.split('\n')) {
        const trimmed = line.trim();
        if (!trimmed || trimmed.startsWith('#')) continue;
        const [key, ...rest] = trimmed.split('=');
        if (key && rest.length > 0) env[key] = rest.join('=');
    }
    return env;
}
